var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"부활의 지팡이를 되찾았다고?","JPN":"復活の杖を取り戻した？","ENG":"The Staff of Resurrection has been recovered?","TWN":"找到復活之杖了？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예. 대신전에서 보낸 전령이 그렇게 전하더군요.","JPN":"はい。大神殿からの伝令がそう伝えてきました。","ENG":"Yes, the messenger from the Great Temple has reported as such.","TWN":"是，殿下，是大神殿派人傳來的消息。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"남쪽 신전의 신전장이 직접 도둑을 체포하고 부활의 지팡이를 되찾아 왔다고 합니다.","JPN":"南方の神殿の神殿長がじかに泥棒を逮捕し、復活の杖を取り戻してきたようです。","ENG":"They have also reported that the Head Priestess of the Southern Temple has personally arrested the thieves and recovered the Staff of Resurrection.","TWN":"據說是南方神殿的祭司長親手抓到小偷，將復活之杖找回來的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"서쪽 신전의 성녀 후보는 아무런 얘기도 없던가?","JPN":"西方の神殿の聖女候補は何も話してなかったのか？","ENG":"Is there no word regarding the candidate for the Sainthood from the Western Temple?","TWN":"西方神殿的聖女候選人什麼話都沒說嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"오늘 새벽에 기도를 드리러 신전 기사들과 함께 대신전을 나선 뒤 행방이 묘연하다 합니다.","JPN":"今日の明け方、祈りを捧げるために神殿の騎士と一緒に大神殿を出た後、行方が知れないそうです。","ENG":"She has been missing since this morning after she left the Great Temple with the temple knights to pray.","TWN":"今天凌晨和神殿騎士一起到大神殿祈禱後，便下落不明。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"호오. 유력한 후보의 실종과 함께 사건을 해결하다니…….","JPN":"ほお。有力候補の失踪とともに事件を解決したと……","ENG":"Oh, is that so? So she has been able to resolve the case while at the same time another prime candidate has gone missing...","TWN":"呵呵，事情解決的同時，有望當選的候選人卻失蹤嗎……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"참으로 공교로운 우연 아닌가, 알렌 경.","JPN":"なんという偶然だろうか。なあ？　アレン卿。","ENG":"Is this not such a convenient coincidence, Sir Allen?","TWN":"真是巧呢，你說是不是，艾倫卿？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하. 이번 일은 그리 쉽게 넘길 사안이 아닙니다.","JPN":"殿下。今回の事件はそう簡単に済まされる案件ではございません。","ENG":"Your Highness, this is an incredibly delicate issue.","TWN":"殿下，這件事不能就這樣輕易放過。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"사제장의 행적이 매우 의심스럽습니다.","JPN":"神殿長の行動が怪しすぎます。","ENG":"The Head Priestess’ conduct is very suspicious.","TWN":"祭司長的形跡非常可疑，"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"출정식을 연기하고 철저하게 이 사건에 대해 조사하시는 것이……","JPN":"出征式を延期し、この事件について徹底的に調査なさった方が……","ENG":"I would advise delaying the ceremony of war and ordering a thorough investigation into this matter...","TWN":"是否將出征儀式延後，先徹查這件事……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아니. 출정식은 예정대로 진행한다.","JPN":"いや。出征式は予定どおり進める。","ENG":"No. The ceremony of war will proceed as planned.","TWN":"不，出征儀式如期舉行。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"온 제국민이 오늘까지 마왕에 맞설 구원 기사단의 출정을 기다려 왔다.","JPN":"すべての帝国民が今日まで魔王に立ち向かう救世騎士団の出征を待ってきたんだ。","ENG":"The entire empire has been waiting to this day for the Knights of Redemption to march against the Demon Lord.","TWN":"全帝國的百姓，都在期待救贖騎士團可以出征對付魔王。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이제 와서 연기한들 불안만 키울 뿐이지.","JPN":"今更引き延ばしても不安が濃くなるだけだ。","ENG":"Delaying the ceremony now will only serve to increase their anxiety.","TWN":"現在說要延後只怕會引發百姓的不滿。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하, 하오나……","JPN":"ですが、殿下……","ENG":"However, Your Highness...","TWN":"可是殿下……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경. 직언을 서슴지 않는 그대의 충성은 높게 평가하고 있다.","JPN":"アレン卿。ためらわず直言するそなたの忠心は高く評価する。","ENG":"Sir Allen. Your loyalty and willingness to be blunt are held in high regard.","TWN":"艾倫卿，我非常欣賞你的忠心和敢於諫言。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 군주라면 어떤 난관도 정면으로 돌파할 수 있어야 하는 법.","JPN":"だが、君主たる者、いかなる困難も正面から乗り越えていかくてはならん。","ENG":"However, a monarch must be able to overcome any obstacle head-on.","TWN":"不過身為一國之君，必須能夠正面迎戰任何難關。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나를 이 정도 일에 흔들릴 정도로 어리석은 군주라 여겼다면 다시 생각할 기회를 주지.","JPN":"私がこの程度のことで揺さぶられるほど愚かな君主だと思ったのなら、考え直す機会を与えてやろう。","ENG":"If you had considered me a foolish king who is easily shaken merely by something like this, then I will give you a chance to reassess me.","TWN":"若你認為我是會因為這點小事就動搖的昏君，那我給你個機會，再重新考慮一下是否要效忠於我吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"들어와라. 샬롯.","JPN":"入れ、シャーロット。","ENG":"Come in, Carlota.","TWN":"夏洛特，進來。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"마르티네즈 백작 영애?","JPN":"マルチネス伯爵令嬢？","ENG":"The daughter of Count Martinez?","TWN":"馬汀尼茲伯爵的千金？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하, 명령하신 임무를 수행하고 왔습니다.","JPN":"殿下、命じられた任務を果たしてまいりました。","ENG":"Your Highness, I have carried out the mission you had ordered.","TWN":"殿下，殿下吩咐的任務已執行完畢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"후후, 몸에서 피 냄새가 진동하는 것을 보니 조사 결과가 꽤 재미있었나 보구나.","JPN":"ふふ、体から血の匂いがたちこめているところをみると、調査結果がずいぶんと面白かったようだな。","ENG":"Oh? Judging by the stench of blood coming from you, the results of your investigation must have been interesting.","TWN":"呵呵，我從你身上聞到一股血腥的味道，想必調查結果應該很有意思吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래, 실상은 어떻게 되어 있더냐?","JPN":"さて、実際どうだった？","ENG":"So, what did you find?","TWN":"說吧，真相究竟為何？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"남쪽 신전을 급습하여 고위 성기사 열두 명을 참살하고 남은 사제들을 심문한 끝에 마왕을 경배하는 제단을 발견했습니다.","JPN":"南方の神殿を急襲し、高位の聖騎士12人を斬殺、残りの司祭を尋問した末、魔王を崇める祭壇を発見しました。","ENG":"I raided the Southern Temple and slaughtered twelve of their high paladins. After interrogating the remaining priests, I discovered an altar dedicated to the worship of the Demon Lord.","TWN":"偷襲南方神殿後殺死12名高階聖騎士，審問其餘的祭司後發現敬拜魔王的祭壇。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"신전장의 배신 증거는 모두 확보하였으며 사제들은 명에 따라 모두 처형하였습니다.","JPN":"神殿長が裏切った証拠はすべて確保し、司祭たちを命に従いすべて処刑いたしました。","ENG":"I have acquired all evidence of the Head Priestess’ betrayal and executed all of the priests, as you had ordered.","TWN":"祭司長罪證確鑿，已奉命將祭司全部處決。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"고위 성기사 열두 명을……? 그대 혼자서 말인가?","JPN":"高位の聖騎士12人を……？　君一人でか？","ENG":"Twelve high paladins...? Do you mean by yourself?","TWN":"12名高階聖騎士……？全是你一個人殺的嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그게 아니지, 알렌 경. 그녀가 고작 열두 명을 상대로 애를 먹었다면 난 아주 실망했을 거다.","JPN":"おいおい、アレン卿。彼女がたった12人を相手に苦戦したのなら私はとてもがっかりしたはずだ。","ENG":"Don’t be surprised, Sir Allen. If she had difficulty facing merely twelve of them, I would have been very disappointed.","TWN":"當然不是囉，艾倫卿。若是她的能力只有這樣，那我會很失望的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯은 전 마르티네즈 백작이 감히 날 상대하기 위해 벼린 칼날이니까.","JPN":"シャーロットは先代のマルチネス伯爵が私と戦わせるために鍛えた刃だからな。","ENG":"Carlota is the blade that Count Martinez dared to hone to wield against me.","TWN":"夏洛特可是前馬汀尼茲伯爵栽培來對付我的武器呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그나저나 샬롯. 어디 말해 보도록. 신전장을 어떻게 하는 것이 좋겠나.","JPN":"ところでシャーロット。話してみろ。神殿長をどうするべきだと思うか？","ENG":"Anyways, Carlota, tell me. What do you think I should do with the Head Priestess?","TWN":"夏洛特，你說說看，你認為該如何處治祭司長？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"질문에 답을 드리는 것도 임무입니까?","JPN":"質問にお答えするのも任務ですか？","ENG":"Is answering your questions also a mission?","TWN":"回答問題也是任務之一嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇게 여겨도 무방하다.","JPN":"そう解釈してもよい。","ENG":"You may consider it as such.","TWN":"你要這麼想也無妨。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"죄송합니다. 모르겠습니다, 전하.","JPN":"申し訳ございません。わかりません、殿下。","ENG":"I’m sorry, Your Highness. I do not know.","TWN":"很抱歉，殿下，我不知道。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흠. 아직은 그 정도인가. 가야 할 길이 멀군.","JPN":"ふむ。まだその程度か。先が長いな。","ENG":"Hmm... So this is all you can manage for now. We still have a long way to go.","TWN":"哼，還是沒什麼進步嗎？看來還有很長的路要走呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"제가……. 전하의 심기를 어지럽혔습니까?","JPN":"私が……　殿下の機嫌を損ねましたか？","ENG":"Did I... say something wrong, Your Highness?","TWN":"我……讓殿下不開心嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"신경 쓸 것 없다. 서서히 깨우쳐 나가면 될 테지. 시간은 충분할 테니.","JPN":"気にすることはない。ゆっくり学んでいけばよい。時間は十分にある。","ENG":"Do not worry about it. You will learn gradually. You have plenty of time.","TWN":"沒事，慢慢恢復吧，還有時間。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"전하, 경기장에 구원자가 되고자 하는 전사들이 집결하였습니다.","JPN":"殿下、競技場に救世主を志望する戦士たちが集結いたしました。","ENG":"Your Highness, the warriors who wish to become the Savior have gathered at the arena.","TWN":"殿下，競技場上已經聚集許多想成為救贖者的戰士。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래. 폐하께서는 모습을 비추셨던가?","JPN":"そうか。陛下はお見えになったか？","ENG":"I see. Has His Majesty made an appearance?","TWN":"好，陛下有露面嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"송구하오나, 전하께 부탁한다는 말씀을 남기신 뒤 다시 잠드셨다고 전해 들었습니다.","JPN":"恐れながら、殿下に頼むというお言葉を残した後に再びお休みになったと聞きました。","ENG":"My apologies, but I have been informed that he had left you in charge of the proceedings before going back to sleep.","TWN":"回殿下，陛下交代這件事由殿下處理後，便再度就寢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……그래. 병세가 더욱 깊어지신 모양이군.","JPN":"……そうか。病状がさらに重くなられたようだな。","ENG":"...I see. It seems that the disease has taken a heavier toll on him.","TWN":"……嗯，看來病情又加重了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경, 가기 전에 내 한 가지만 묻지.","JPN":"アレン卿、行く前に一つだけ聞こう。","ENG":"Sir Allen, before we go, I would like to ask one question.","TWN":"艾倫卿，在你離開之前，我有個問題要問你。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"말씀하십시오. 전하.","JPN":"何なりと。殿下。","ENG":"Yes, Your Highness?","TWN":"殿下請說。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이제부터 저 경기장에서 마지막 한 명이 남을 때까지 서로의 힘을 겨루겠지.","JPN":"これからあの競技場では最後の一人となるまでお互い競い合うだろう。","ENG":"Soon, they will be testing each other’s strength until only one remains in the arena.","TWN":"接下來他們就會在競技場上彼此較勁，直到最後一人勝出為止。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저기 모인 자들이 무엇을 위해 구원자가 되려 하는지 알고 있나?","JPN":"あそこに集った者たちは何のために救世主になろうとするのか、その理由を知っているか？","ENG":"Do you know why those gathered in the arena aspire to be the Savior?","TWN":"你認為那些人為什麼想成為救贖者？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이유는 각기 다를 겁니다.","JPN":"理由は各々違うはずです。","ENG":"Each will have its own reason.","TWN":"理由各有不同。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"누군가는 둘도 없는 명예를 위해, 혹은 구원자란 이름이 가진 권력을 위해…….","JPN":"誰かはこの上ない名誉のため、あるいは救世主という名が持つ権力のため……","ENG":"Some for the incomparable honor, others for the power that the title of Savior holds...","TWN":"有人是為至高無上的榮譽，有人是為救贖者之名所帶來的權利……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"혹은 그저 순수하게 사람들을 지키기 위해서 온 이들도 있을지 모르겠군요.","JPN":"または、ただ純粋に人を守るために来た者もいるかもしれません。","ENG":"And maybe even a few who purely wish to protect people.","TWN":"或許也有人是單純想守護百姓。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그런 자가 있다면 이 두 눈으로 확인하고 싶군.","JPN":"そのような者がいるというなら、この目で確かめてみたいものだな。","ENG":"If there is such a person, I wish to see them with my own two eyes.","TWN":"若真有這種人，那我倒想親眼見見。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경. 나는 모두를 이끌기 위해 저 위에 설 것이다.","JPN":"アレン卿。私はみなを率いるためにあの上に立つ。","ENG":"Sir Allen, I will stand at the top to lead everyone.","TWN":"艾倫卿，我要站在那之上帶領大家。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하께오선 구원자라는 이름 없이도 능히 저들을 이끄실 수 있을 겁니다.","JPN":"殿下は救世主の名がなくても十分にあの者たちを率いることができるでしょう。","ENG":"You are capable of leading us even without the title of Savior, Your Highness.","TWN":"殿下不需要救贖者的名義，也能夠帶領大家的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하늘에 태양이 둘일 수 없듯이 제국의 정상에 군림하는 자는 하나여야 한다.","JPN":"天に二つの太陽がないように、帝国の頂上に君臨する者は一人であるべきだ。","ENG":"Just as there cannot be two suns in the sky, only one must rule at the top of an empire.","TWN":"如同天上只有一顆太陽，帝國的天子應該也只有一位。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 자비도, 구원도. 오직 군림하는 자만이 베풀 수 있는 법이지.","JPN":"そして慈悲も、救いも。ただ君臨する者のみが与えうるものである。","ENG":"Mercy. Salvation. These can only be given by the one that rules.","TWN":"而且無論慈悲或救贖，也唯有天子能夠施捨。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그럼 가 볼까. 황족의 의무를 수행하러.","JPN":"それでは行こうか。皇族の任務を果たすために。","ENG":"Then, it's time to go to perform our imperial duties.","TWN":"走吧，我要去執行皇室的義務。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};